<df-radar-chart dataset='{"title":"AI 智能体综合能力评测","indicators":[{"name":"逻辑推理","max":100},{"name":"代码编写","max":100},{"name":"文本创作","max":100},{"name":"知识记忆","max":100},{"name":"工具调用","max":100}],"values":[92, 85, 95, 90, 88]}'></df-radar-chart>

